import EfiPy2 as EfiPy
import corepy.arch.x86_64.isa as x86
import corepy.arch.x86_64.types.registers as reg
import corepy.arch.x86_64.platform as env
import corepy.arch.x86_64.lib.memory as mem
from EfiPy2.MdePkg.Protocol.MpService import EFI_AP_PROCEDURE 

class X86ProcessorClass (type):

  def _GetLocalApicAddress (cls):

    ApicSignature = b'APIC'

    from EfiPy2.Lib.Acpi.AcpiApicParser import AcpiApicParser
    from EfiPy2.Lib.Acpi.AcpiRetrieve import ExtractTable

    ApicRaw = ExtractTable (ApicSignature, 0)
    ApicObj, ApicType = AcpiApicParser (ApicRaw)
    cls._LocalApicAddress = ApicObj.LocalApicAddress

  def _BuildIndexDataProcedure (cls):

    ############################################################################
    #
    # Function: IndexDataw8
    #
    # Input:  UINT32 (IndexOffset), UINT32 (DataOffset), UINT32 (IndexValue), UINT32 (DataValue & 0xFF)
    # Output: None
    #
    cls._IndexDataw8CorePrgm = env.Program()
    cls._IndexDataw8CoreCode = cls._IndexDataw8CorePrgm.get_stream()

    cls._IndexDataw8CoreCode.add(x86.push(reg.rdi))
    cls._IndexDataw8CoreCode.add(x86.mov(reg.rdi, mem.MemRef(reg.rbp, -0x20)))

    #
    # Start to fill Index Offset and Index Value
    #
    cls._IndexDataw8CoreCode.add(x86.mov(reg.edx, mem.MemRef(reg.rdi, 0, data_size = 32)))     # IndexOffset
    cls._IndexDataw8CoreCode.add(x86.mov(reg.eax, mem.MemRef(reg.rdi, 8, data_size = 32)))     # IndexValue

    cls._IndexDataw8CoreCode.add(x86.out(reg.dx, reg.eax))

    #
    # Start to fill Data Offset and Data Value
    #
    cls._IndexDataw8CoreCode.add(x86.mov(reg.edx, mem.MemRef(reg.rdi, 4, data_size = 32)))     # DataOffset
    cls._IndexDataw8CoreCode.add(x86.mov(reg.eax, mem.MemRef(reg.rdi, 12, data_size = 32)))     # DataValue

    cls._IndexDataw8CoreCode.add(x86.out(reg.dx, reg.al))

    cls._IndexDataw8CoreCode.add(x86.pop(reg.rdi))

    cls._IndexDataw8CorePrgm.add (cls._IndexDataw8CoreCode)
    cls._IndexDataw8CoreAddr, cls._IndexDataw8CoreBytes = cls._IndexDataw8CorePrgm.get_code_bytes ()

    cls._IndexDataw8CoreFunc = EFI_AP_PROCEDURE (cls._IndexDataw8CoreAddr)

    ############################################################################
    ############################################################################
    #
    # Function: IndexDataw16
    #
    # Input:  UINT32 (IndexOffset), UINT32 (DataOffset), UINT32 (IndexValue), UINT32 (DataValue & 0xFFFF)
    # Output: None
    #
    cls._IndexDataw16CorePrgm = env.Program()
    cls._IndexDataw16CoreCode = cls._IndexDataw16CorePrgm.get_stream()

    cls._IndexDataw16CoreCode.add(x86.push(reg.rdi))
    cls._IndexDataw16CoreCode.add(x86.mov(reg.rdi, mem.MemRef(reg.rbp, -0x20)))

    #
    # Start to fill Index Offset and Index Value
    #
    cls._IndexDataw16CoreCode.add(x86.mov(reg.edx, mem.MemRef(reg.rdi, 0, data_size = 32)))     # IndexOffset
    cls._IndexDataw16CoreCode.add(x86.mov(reg.eax, mem.MemRef(reg.rdi, 8, data_size = 32)))     # IndexValue

    cls._IndexDataw16CoreCode.add(x86.out(reg.dx, reg.eax))

    #
    # Start to fill Data Offset and Data Value
    #
    cls._IndexDataw16CoreCode.add(x86.mov(reg.edx, mem.MemRef(reg.rdi, 4, data_size = 32)))     # DataOffset
    cls._IndexDataw16CoreCode.add(x86.mov(reg.eax, mem.MemRef(reg.rdi, 12, data_size = 32)))     # DataValue

    cls._IndexDataw16CoreCode.add(x86.out(reg.dx, reg.eax))

    cls._IndexDataw16CoreCode.add(x86.pop(reg.rdi))

    cls._IndexDataw16CorePrgm.add (cls._IndexDataw16CoreCode)
    cls._IndexDataw16CoreAddr, cls._IndexDataw16CoreBytes = cls._IndexDataw16CorePrgm.get_code_bytes ()

    cls._IndexDataw16CoreFunc = EFI_AP_PROCEDURE (cls._IndexDataw16CoreAddr)

    ############################################################################
    ############################################################################
    #
    # Function: IndexDataw32
    #
    # Input:  UINT32 (IndexOffset), UINT32 (DataOffset), UINT32 (IndexValue), UINT32 (DataValue)
    # Output: None
    #
    cls._IndexDataw32CorePrgm = env.Program()
    cls._IndexDataw32CoreCode = cls._IndexDataw32CorePrgm.get_stream()

    cls._IndexDataw32CoreCode.add(x86.push(reg.rdi))
