    cls._IndexDataw32CoreCode.add(x86.out(reg.dx, reg.eax))

    #
    # Start to fill Data Offset and Data Value
    #
    cls._IndexDataw32CoreCode.add(x86.mov(reg.edx, mem.MemRef(reg.rdi, 4, data_size = 32)))     # DataOffset
    cls._IndexDataw32CoreCode.add(x86.mov(reg.eax, mem.MemRef(reg.rdi, 12, data_size = 32)))     # DataValue

    cls._IndexDataw32CoreCode.add(x86.out(reg.dx, reg.eax))

    cls._IndexDataw32CoreCode.add(x86.pop(reg.rdi))

    cls._IndexDataw32CorePrgm.add (cls._IndexDataw32CoreCode)
    cls._IndexDataw32CoreAddr, cls._IndexDataw32CoreBytes = cls._IndexDataw32CorePrgm.get_code_bytes ()

    cls._IndexDataw32CoreFunc = EFI_AP_PROCEDURE (cls._IndexDataw32CoreAddr)

    ############################################################################
    #
    # Function: IndexDatar8 (Read)
    #
    # Input:  UINT32 (IndexOffset), UINT32 (DataOffset), UINT32 (IndexValue), UINT32 (DataValue & 0xFF)
    #
    cls._IndexDatar8CorePrgm = env.Program()
    cls._IndexDatar8CoreCode = cls._IndexDatar8CorePrgm.get_stream()

    cls._IndexDatar8CoreCode.add(x86.push(reg.rdi))
    cls._IndexDatar8CoreCode.add(x86.mov(reg.rdi, mem.MemRef(reg.rbp, -0x20)))

    #
    # Start to fill Index Offset and Index Value
    #
    cls._IndexDatar8CoreCode.add(x86.mov(reg.edx, mem.MemRef(reg.rdi, 0, data_size = 32)))     # IndexOffset
    cls._IndexDatar8CoreCode.add(x86.mov(reg.eax, mem.MemRef(reg.rdi, 8, data_size = 32)))     # IndexValue

    cls._IndexDatar8CoreCode.add(x86.out(reg.dx, reg.eax))

    #
    # Start to fill Data Offset and Data Value
    #
