    cls._IndexDatar8CoreCode.add(x86.xor(reg.eax, reg.eax))
    cls._IndexDatar8CoreCode.add(x86.in_(reg.al, reg.dx))

    cls._IndexDatar8CoreCode.add(x86.mov(mem.MemRef(reg.rdi, 12, data_size = 32), reg.eax))

    #
    # Build Function
    #
    cls._IndexDatar8CoreCode.add(x86.pop(reg.rdi))

    cls._IndexDatar8CorePrgm.add (cls._IndexDatar8CoreCode)
    cls._IndexDatar8CoreAddr, cls._IndexDatar8CoreBytes = cls._IndexDatar8CorePrgm.get_code_bytes ()

    cls._IndexDatar8CoreFunc = EFI_AP_PROCEDURE (cls._IndexDatar8CoreAddr)

    ############################################################################
    #
    # Function: IndexDatar16 (Read)
    #
    # Input:  UINT32 (IndexOffset), UINT32 (DataOffset), UINT32 (IndexValue), UINT32 (DataValue & 0xFF)
    #
    cls._IndexDatar16CorePrgm = env.Program()
    cls._IndexDatar16CoreCode = cls._IndexDatar16CorePrgm.get_stream()

    cls._IndexDatar16CoreCode.add(x86.push(reg.rdi))
    cls._IndexDatar16CoreCode.add(x86.mov(reg.rdi, mem.MemRef(reg.rbp, -0x20)))

    #
    # Start to fill Index Offset and Index Value
    #
    cls._IndexDatar16CoreCode.add(x86.mov(reg.edx, mem.MemRef(reg.rdi, 0, data_size = 32)))     # IndexOffset
    cls._IndexDatar16CoreCode.add(x86.mov(reg.eax, mem.MemRef(reg.rdi, 8, data_size = 32)))     # IndexValue

    cls._IndexDatar16CoreCode.add(x86.out(reg.dx, reg.eax))

    #
    # Start to fill Data Offset and Data Value
    #
    cls._IndexDatar16CoreCode.add(x86.mov(reg.edx, mem.MemRef(reg.rdi, 4, data_size = 32)))     # DataOffset

    cls._IndexDatar16CoreCode.add(x86.xor(reg.eax, reg.eax))
    cls._IndexDatar16CoreCode.add(x86.in_(reg.ax, reg.dx))

    cls._IndexDatar16CoreCode.add(x86.mov(mem.MemRef(reg.rdi, 12, data_size = 32), reg.eax))

