    cls._Iow8CoreCode.add(x86.mov(reg.rdi, mem.MemRef(reg.rbp, -0x20)))

    cls._Iow8CoreCode.add(x86.mov(reg.edx, mem.MemRef(reg.rdi, 0, data_size = 32)))     # rdi[0]: Index, rdi[4]: Value
    cls._Iow8CoreCode.add(x86.mov(reg.eax, mem.MemRef(reg.rdi, 4, data_size = 32)))

    cls._Iow8CoreCode.add(x86.out(reg.dx, reg.al))

